package com.twksos.react;

import android.content.BroadcastReceiver;
import android.content.Context;
import android.content.Intent;
import android.content.IntentFilter;
import android.telephony.TelephonyManager;
import android.util.Log;

import com.facebook.react.bridge.ReactApplicationContext;
import com.facebook.react.bridge.ReactContextBaseJavaModule;
import com.facebook.react.bridge.ReactMethod;
import com.facebook.react.modules.core.DeviceEventManagerModule;

class CallReceiver extends BroadcastReceiver {
    private final CallDetectorModule detectorModule;

    CallReceiver(CallDetectorModule detectorModule) {
        this.detectorModule = detectorModule;
    }

    @Override
    public void onReceive(Context context, Intent intent) {
        if (intent != null && TelephonyManager.ACTION_PHONE_STATE_CHANGED.equals(intent.getAction())) {
            String state = intent.getStringExtra(TelephonyManager.EXTRA_STATE);
            this.detectorModule.notifyCallStateChange(state);
        }
    }
}

public class CallDetectorModule extends ReactContextBaseJavaModule {
    private static final String TAG = "RCTCallDetector";
    private CallReceiver callReceiver;

    public CallDetectorModule(ReactApplicationContext context) {
        super(context);
    }

    @Override
    public String getName() {
        return "RCTCallDetector";
    }

    @ReactMethod
    public void startListener() {
        if (this.callReceiver == null) {
            this.callReceiver = new CallReceiver(this);
            IntentFilter filter = new IntentFilter();
            filter.addAction(TelephonyManager.ACTION_PHONE_STATE_CHANGED);
            try {
                getReactApplicationContext().registerReceiver(this.callReceiver, filter);
            } catch (Exception e) {
                Log.e(TAG, "Failed to register phone state receiver", e);
            }
        }
    }

    @Override
    public void onCatalystInstanceDestroy() {
        super.onCatalystInstanceDestroy();
        if (this.callReceiver != null) {
            try {
                getReactApplicationContext().unregisterReceiver(this.callReceiver);
            } catch (Exception e) {
                Log.w(TAG, "Failed to unregister phone state receiver", e);
            }
            this.callReceiver = null;
        }
    }

    void notifyCallStateChange(String state) {
        if (state == null) {
            return;
        }
        ReactApplicationContext context = getReactApplicationContext();
        if (context.hasActiveCatalystInstance()) {
            DeviceEventManagerModule.RCTDeviceEventEmitter emitter = 
                context.getJSModule(DeviceEventManagerModule.RCTDeviceEventEmitter.class);
            
            String jsState = "Disconnected";
            if (state.equals(TelephonyManager.EXTRA_STATE_IDLE)) {
                jsState = "Disconnected";
            } else if (state.equals(TelephonyManager.EXTRA_STATE_OFFHOOK)) {
                jsState = "Connected";
            } else if (state.equals(TelephonyManager.EXTRA_STATE_RINGING)) {
                jsState = "Incoming";
            }
            
            try {
                emitter.emit("EventPhoneCallChange", jsState);
            } catch (Exception e) {
                Log.e(TAG, "Error emitting call event to JS", e);
            }
        }
    }
}